### Function Type Expressions

Function types describe the signature of a function: parameter types and return type.

### Syntax

```typescript
type GreetFn = (name: string) => string;

let greet: GreetFn = (name) => `Hello, ${name}`;
```

### Call Signatures

You can also use call signatures in object types:

```typescript
type DescribableFunction = {
  description: string;
  (someArg: number): boolean;
};

function doSomething(fn: DescribableFunction) {
  console.log(fn.description + " returned " + fn(6));
}
```

### Construct Signatures

Functions that can be called with `new`:

```typescript
type SomeConstructor = {
  new (s: string): SomeObject;
};

function fn(ctor: SomeConstructor) {
  return new ctor("hello");
}
```

### Parameter Destructuring

```typescript
type User = { name: string; age: number };

function printUser({ name, age }: User): void {
  console.log(`${name} is ${age} years old`);
}
```

### Rest Parameters Type

```typescript
function sum(...numbers: number[]): number {
  return numbers.reduce((a, b) => a + b, 0);
}
```

> **Key Point:** The arrow `=>` in function types separates parameters from return type, not the function body.

codeExample:
// Function type alias
type Calculator = (a: number, b: number) => number;

const add: Calculator = (x, y) => x + y;
const multiply: Calculator = (x, y) => x * y;

// Call signature
interface Logger {
  (message: string, level?: string): void;
}

const log: Logger = (msg, level = "info") => {
  console.log(`[${level}] ${msg}`);
};

// Parameter destructuring with types
function sum({ a, b }: { a: number; b: number }): number {
  return a + b;
}
